# Step 5: Seed source docs into app-events index
kubectl -n elasticsearch exec curl-test -- /bin/sh -c '
cat <<EOF | curl -s -XPOST http://es-http.elasticsearch.svc:9200/_bulk -H "Content-Type: application/x-ndjson" --data-binary @-
{"index":{"_index":"app-events"}}
{"service":"api","@timestamp":"2026-01-01T00:00:00Z"}
{"index":{"_index":"app-events"}}
{"service":"web","@timestamp":"2026-01-01T00:00:01Z"}
{"index":{"_index":"app-events"}}
{"service":"api","@timestamp":"2026-01-01T00:00:02Z"}
EOF
' 2>/dev/null

# Step 6: Create the events-by-service transform
kubectl -n elasticsearch exec curl-test -- curl -s -XPUT \
  "http://es-http.elasticsearch.svc:9200/_transform/events-by-service" \
  -H "Content-Type: application/json" \
  -d '{
    "source": {"index": "app-events"},
    "dest": {"index": "app-events-rollup"},
    "pivot": {
      "group_by": {"service": {"terms": {"field": "service.keyword"}}},
      "aggregations": {"event_count": {"value_count": {"field": "service.keyword"}}}
    },
    "sync": {"time": {"field": "@timestamp", "delay": "1s"}}
  }' 2>/dev/null | python3 -m json.tool

